INSERT INTO routes (id, mountain_id, name, difficulty, season, description) VALUES
  ('01f1c4ff-ee43-5816-b9ac-329f049e3698', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Вост. с пер. Местийский (А.Золотарёв)', 3, 'Июль — сентябрь', 'Категория: 3Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('fd584ec5-9be3-5380-8f1a-eef6dd944e13', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Вост. по С-В ребру Восточного плеча (А.Наумов)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('46d23bde-4948-5e49-9743-59e9263edf9b', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Вост. по Северной стене Восточного плеча (Ю.Черносливин)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('75c7fe46-713c-5ba0-9353-7801ed37ba31', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Вост. по правому ребру Сев. стены Вост. плеча (В.Артомонов)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('0b12c130-d232-5c3b-980d-aac6f82ebfb1', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Вост. по правому ребру Северной стены (Е.Манучаров)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('51ed95ff-64d5-5a54-962a-93bb52ca25e2', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Вост. по скальным островам Северной стены (Ю.Черносливин)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('b421a17d-e894-5b18-a7d8-ec49076f31c1', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Гл. по северной стене (В.Абалаков), «Классика»', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау. Перепад высот: 700 м (от «Абалаковских» ночёвок до вершины, ориентировочно). Протяжённость: 1000 м.

Участки V кат. сл.: 180 м, VI кат. сл. — 40 м
Средняя крутизна: ключевых участков — 80°, основной части маршрута — 60°, всего маршрута — 63°
Описание маршрута:
С бивуака на моренных отложениях, находящихся под Северной стеной (т.н. «Центральные скалы» или «Абалаковские» ночёвки) вверх по некрутому закрытому леднику к большому бергшрунду. Выход на маршрут в 0:30.
R0–R1: Бергшрунд преодолевается по снежно-ледовому мосту. Подъём вверх по снежно-ледовому склону крутизной 50–55° (фирн, страховка через ледобуры) протяжённостью 300 м в направлении скального выхода «ромб».
R1–R2: На вершину «ромба» выход сначала по обледенелым скалам внутреннего угла в нижней части (френды, закладки, крючья, ИТО А2), потом (R2-R4) по правому краю широкого кулуара между стеной и «ромбом» (45°, скалы, фирн, лед). Лёд очень твёрдый, скалывается линзами как натечный.
R4–R5: От «ромба» под основание скального сброса Северной стены по ледовому склону с выходами заснеженных скал и камней.
R5–R6: От нижней части Северной стены — траверс вправо вверх по внутреннему углу стенки 1-ой ступени трёхступенчатого поликлисклона. Скалы, местами натечный лёд (френды, крючья, закладки, ИТО).
R6–R7: Движение вправо вверх, с прохождением небольших (10–15 метров) стенок и выход на нижнее плечо Северной стены, правее Огурцов.
R7–R8: С третьей ступеньки плеча вверх-влево по разрушенному 100–120-метровому крутому скальному гребешку средней трудности к полке-кулуару, постепенно переходящему в крутой заснеженный жёлоб («живые» камни), выход до площадки под камином (страховка через ледобуры, скальные крючья и закладки).
R10–R11: С площадки вверх по камину, очень трудное лазание, в середине дня из-за таяния снежников сверху камина, скользкие и мокрые скалы, выход на маленькую площадку (ИТО, шлямбура, френды).
R11–R13: От камина по крутым скалам и плитам средней и выше средней трудности (много «живых» камней), выйти к ночёвке левее жандарма «Палец».
R14–R15: От бивуака вверх по крутым заснеженным скалам Северного гребня средней трудности — 150 метров до основного «ножа».
R16–R18: Пройти небольшую горизонтальную перемычку (10 м) с карнизом и выйти на крутой 100-метровый острый снежный гребень «нож».
R18–R19: Пройдя «нож», от основания вершинной башни движение вверх по чередующимся скальным стенкам и наклонным снежным полкам.
R19–R20: Далее двигаться по нешироком скальному гребешку и вверху, обходя вершинную башню слева по внутреннему углу, подниматься на в. Уллутау Главная.
Спуск с вершины по гребню в сторону Западной вершины и далее на перевал Гарваш. 3 к. сл.'),
  ('80ac07ca-6155-556f-ac67-64e72e266985', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Гл. по скальным островам Северной стены и Западному гребню (В.Мальцев), «Бурлуцкого»', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: ледово-снежный. Вершина: Уллутау.

Описание маршрута:
R1: От исходного бивака, на «Центральных» ночёвках, вверх в направлении скального «ромба». Снежно-ледовый склон средней трудности, большое количество трещин (связки!). Движение одновременное, обязательно кошки и ледоруб.
R1–R2: Преодоление большого бергшрунда, страховка через ледобуры. Далее движение вправо вверх по крутому трудному ледовому склону (в нижней части присыпан снегом) в направлении 2-го скального острова м-та Мальцева. Здесь и далее движение попеременное, крючьевая страховка, для прохождения используются ледовые молотки.
R2–R3: Узкий крутой ледовый кулуар, лазание трудное (ключевое место маршрута). Для первого требуется отличная техника хождения на передних зубьях. Выход из кулуара вправо на вершину небольшого скального островка.
R3–R4: Движение вверх влево по крутому трудному ледовому склону на вершину 2-го скального острова м-та Мальцева (контрольный тур, площадка для сидячей ночёвки). Много вмёрзших в лёд камней (камнеопасно!).
R4–R5: Движение вверх по крутому трудному ледовому склону, много вмёрзших камней.
R5–R6: Трудный траверс вверх влево по крутому ледовому склону между вершиной 3-го скального острова м-та Мальцева и скальным поясом Западного гребня Уллутау Главной.
R6–R7: Суживающийся крутой трудный ледовый кулуар, в верхней части много «живых» камней и блоков. Выход на Западный гребень. Использование ледовых молотков, «перил», скальные выступы гребня.
R7–R8: Движение влево по заледенелому скальному гребню средней трудности. Жандарм преодолевается в лоб. Движение одновременное, много выступов для страховки. На вершине есть хорошая площадка.'),
  ('c1e594c9-6e3b-5d56-85ec-a1233ba0460d', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Гл. через скальный Остров (В. Ли)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.

Описание маршрута:
R0: От «Чегетских ночёвок» выйти на ледник Уллутау и по его плато (закрытые трещины) не доходя «Центральных площадок» свернуть вправо под Северную стену Уллутау, где крутизна склона 35° постепенно увеличивается и дойти до бергшрунда. Его преодолеть с помощью искусственных точек опоры (6 м).
R1: Затем подняться по натечному ледовому склону в направлении «хвоста» скального острова (160 м.).
R2: Далее по скалам, залитым натечным льдом, дойти до косой полки. (70 м)
R3–R4: С полки двигаться вверх вправо до внутреннего угла. Не входя во внутренний угол двигаться влево по скалам выше средней трудности до небольшой полки на двоих (135 м).
R5: Далее по неявно выраженному ребру скального острова, выйти на небольшую полку. Ночёвка! Контрольный тур!
R6: После ночёвки скальную башню обойти слева по крутому ледовому склону (40 м).
R7: Далее по ледовому склону дойти до небольшой треугольной башни (300 м).
R8: Затем вправо вверх двигаться в направлении скала жандарма «Утюг». С перемычки жандармов «Ромб» и «Утюг» летят камни (60 м).
R9: Далее по скалам средней трудности двигаться в направлении влево-вверх к камину (40 м).
R10: Камин с «живыми» камнями, в верхней части переходит в монолит, льётся вода, лазание усложняется. От верхней части камина уходить влево и выйти чуть выше перемычки двух жандармов (35м).
R11: По полке 25м, влево и завернув за угол подняться вверх по простым единичным скалам на следующую полку. На полке сверху мелкая сыпуха, которая после непогоды может быть присыпана снегом.
На гребне бивуак. Далее по маршруту 4а к.тр. выйти на вершину Уллутау Главная.
Спуск по гребню к перевалу Гарваш по маршруту 4А.'),
  ('f713d726-cbe9-5119-9740-2852ceccf3f4', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Г. по Северной стене через «Рак» (Д.Ласкавый)', 5, 'Июль — сентябрь', 'Категория: 5Б. Тип: комбинированный. Вершина: Уллутау.'),
  ('270f2685-573f-5feb-b6a7-71c03bf15948', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Зап. по Северной стене (Э.Липень)', 5, 'Июль — сентябрь', 'Категория: 5А. Тип: комбинированный. Вершина: Уллутау.'),
  ('4e3ce503-f788-563f-96b6-73a6f129e4dd', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Зап. по Северо-Западной стене (Д.Гудков)', 4, 'Июль — сентябрь', 'Категория: 4Б. Тип: комбинированный. Вершина: Уллутау.

Описание маршрута (по Доске):
R0: С Чегетских ночёвок по разорванной западной части ледника Уллутау в сторону перевала Гарваш, обходя многочисленные трещины, до выхода на площадки большого скального острова (Хицана). От Чегетских ночёвок 30–50 минут.
R1: От исходного бивака на «Хицане» траверсом влево, пересекая плато ледника, подойти к началу кулуара, находящемуся напротив Хицана и метров 15–20 выше него. По кулуару 30–40 м вверх, затем 80 м по бараньим лбам, далее по системе полок и по сыпухе выйти на «Доску». Здесь под большим камнем есть место под палатку. От «Хицана» 2–3 часа.
R2: Далее вначале по пологому постепенно увеличивающему крутизну ледово-снежному Северо-западному склону 500–600 м вверх под скальный взлёт основного гребня массива. Далее по крутым ледово-снежным склонам, вдоль скальных гребешков, 150–200 м вверх влево в ярко выраженный провал основного гребня массива Уллутау. От начала «Доски» 2–3 часа.
R3: На гребне свернуть вправо и по пологому острому, местами заснеженному, возможно обледенелому скальному гребню с многочисленными жандармами взойти на вершину Уллутау Западная. От места выхода на гребень 1–1,5 часа.'),
  ('c7028de0-973d-5132-a58f-f0fe92a4a892', '684acd74-04ea-58dc-bc27-34eff0f79db6', 'Уллутау Зап. по Западному гребню (Р. Роллестоун)', 2, 'Июль — сентябрь', 'Категория: 2Б. Тип: комбинированный. Вершина: Уллутау.

Описание: Спуск с вершины Уллутау по Западному гребню на перевал Гарваш (маршрут 2Б).
Путь спуска с вершины Уллутау по Западному гребню
Описание: От Западной вершины пройти немного вперёд через предвершинный взлёт, далее уйти в кулуар, идущий в Сванетию, по нему 80 метров до того места, где кулуар сильно расширяется, тут свернуть направо и траверсировать в сторону Зубьев (ярко выраженного «окна в заборе»), пройдя через которые попадаешь на снежные склоны Западного гребня и движешься по ним в сторону перевала Гарваш.'),
  ('e8299740-c73b-5899-b32e-cb430c118c43', 'b51bfc01-1d48-571f-8374-662f246ccaae', '— Лацга по Восточному гребню', 3, 'Июль — сентябрь', 'Категория: 3А. Тип: комбинированный. Вершина: Лацга.

Описание маршрута:
R0: От площадок перевала Гарваш подойти под Восточный гребень вершины Лацга. По 80–90-метровой осыпи подойти к первому скальному взлёту Восточного гребня.
R1: По простым, местами средней трудности скалам первого взлёта Восточного гребня 200–250 м вверх под жандарм Палец.
R2: Палец обходить слева. Сразу за ним траверсировать горловину кулуара уходящего влево-вниз и далее вправо вверх по монолитным скалам средней трудности 60–80 метров под второй взлёт Восточного гребня. Второй взлёт обходить сначала траверсом 20 м по полкам влево, затем вправо под стеной и 18–20 м вверх на взлёт.
R3–R4: Отсюда по осыпному (местами заснеженному) пологому 150-метровому Восточному гребню подойти к небольшому провалу в гребне с уходящими в обе стороны кулуарами. Здесь ключевое место маршрута — 5-ти метровая стенка с косой расщелиной.
R5–R6: Далее мимо явно выраженного спускового кулуара слева (2А) вверх по широкому снежному плато с небольшими взлётами подойти к крутому, в зависимости от сезона, ледовому или фирновому 70–80-ти метровому взлёту на предвершинный гребень. Подниметесь по нему на узкий снежный гребешок, сворачиваете налево и по гребешку выходите на вершину Лацга.'),
  ('d178930b-65f4-56ef-a77a-bf401f3de4cb', 'baa49315-3787-516a-b157-6613eade4a09', '— Адырсу по Северо-Западному гребню', 3, 'Июль — сентябрь', 'Категория: 3Б. Тип: комбинированный. Вершина: Адырсу.

Описание маршрута:
Из а/п «Уллутау» по Местийской тропе мимо местийских ночёвок до правобережной морены ледника Адырсу. По морене дойти до «турика» напротив характерных «рыжих» скал слева. Здесь повернуть влево, пересечь моренный карман и по осыпям подняться к ночёвкам «У рыжих скал».
От «Рыжих скал» по конечной и правобережной моренам безымянного ледника дойти до башни отрога пика Озерный. Затем по склонам (с рядом кулуаров) в Химик до крутого ледового языка ледника Адырсу. На ледник подниматься по скалам слева и в дальнейшем придерживаться левой стороны. Пересечь ледник в левой по ходу части, придерживаясь скал, и выйти к началу снежного кулуара, ведущего к перемычке седловинного гребня между вершинами Химик и Адырсу. Кулуар шириной 10–12м, протяжённость 3–4 верёвки, крутизной 40–45°. На перемычке возможна организация бивуака.
Далее по простым скалам седловинного гребня до второй перемычки между вершинами Химик и Адырсу (40–60 мин). Место под палатку. Далее на пути от перемычки вначале встречаются три «жандарма», из которых первый проходится «в лоб» по простым монолитным скалам и наклонным плитам, на которых возможен натечный лёд. Два последующих жандарма обходятся справа по ходу по полкам. Скалы третьего жандарма более разрушенные. За третьим жандармом начинается ключевое место маршрута (2 верёвки). Сначала снежно-ледовый взлёт крутизной 45–50° (одна верёвка). Затем по монолитным скалам гребня в узкий заснеженный скальный кулуар 10–15 м, залитый натечным льдом, после кулуара направо 7–10 м по трудным скалам (вторая верёвка).
Далее подъём на предвершинную башню и спуск с неё осуществляется по лёгким монолитным скалам с хорошими выступами и зацепами на снежных предвершинный гребень. Гребень пологий вначале, становится круче к предвершинному взлёту до 35–40°. Следует опасаться нависающих с подветренной стороны карнизов, двигаясь на 8–10 м ниже видимой границы гребня. Далее подъём на предвершинную башню. Подниматься на в. Адырсу.'),
  ('dcbfc598-2217-5c23-9a10-53873a7e9185', '1546945c-eba7-5f41-8c64-c446145e013c', '— Химик по Восточному гребню', 2, 'Июль — сентябрь', 'Категория: 2Б. Тип: комбинированный. Вершина: Химик.

Описание маршрута:
Из а/п «Уллутау» по Местийской тропе мимо местийских ночёвок до правобережной морены ледника Адырсу. По морене дойти до «турика» напротив характерных «рыжих» скал. Повернуть влево, пересечь моренный карман и по осыпям подняться к ночёвкам «У рыжих скал».
От «Рыжих скал» — по конечной и правобережной моренам безымянного ледника до башни отрога пика Озерный. Затем по склонам (с рядом кулуаров) в Химик до крутого ледового языка ледника Адырсу. На ледник подниматься по скалам слева. Пересечь ледник в левой по ходу части и выйти к началу снежного кулуара к перемычке седловинного гребня между вершинами Химик и Адырсу. Далее — в узкий 80-метровый кулуар Восточного гребня в. Химик.
В конце кулуара свернуть вправо и обойдя слева скальные выступы большого жандарма по кромке скал и осыпного, покрытого снегом и натечным льдом склона, подняться на гребень.
Далее влево по простым монолитным скалам гребня выход на в. Химик.
От хижины до перемычки 3–4 часа. От перемычки до в. Химик 1,5 часа.'),
  ('744ab458-d936-5434-acd5-6094d50fdec0', '1546945c-eba7-5f41-8c64-c446145e013c', '— Химик по левому склону Северного гребня', 4, 'Июль — сентябрь', 'Категория: 4Б. Тип: комбинированный. Вершина: Химик.

Описание маршрута:
Маршрут проходит по левому контрфорсу (из 3-х спускающихся к леднику Юном-Су). Начало — напротив средних Кичкидарских ночёвок. С ледника путь идёт к левой части контрфорса и далее на широкую осыпную террасу. С террасы по осыпной полке влево до ребра контрфорса, по ребру 2 верёвки вверх под небольшую стенку. У её основания вправо во внутренний угол и по нему вверх.
Дальнейшее движение под основание нависающей стены. Вдоль её основания проходит широкая косая щель, круто идущая вверх. Щель заканчивается пробкой и вертикальной стенкой (3 м). Пробку обходить слева. За стенкой почти вертикальная стенка с хорошими зацепками (правее нависающей скалы).
Далее по полкам (10 м) во внутренний угол и по нему влево вверх, придерживаясь левой стороны контрфорса до небольшой вертикальной серой стенки, у основания которой хорошая площадка. В углу площадки лежит качающаяся плита. С плиты выход на стенку и далее по разрушенным скалам на нависающую скалу — «клюв». На площадке «клюва» контрольный тур. До тура 14 верёвок. Имеется площадка для ночёвки. От начала маршрута — 4–5 часов.
От контрольного тура вверх 70 м до начала снежного гребня. По нему пологий спуск вниз. Далее по длинному снежному гребню, ведущему к вершинной башне. Перед башней — бергшрунд. От контрольного тура до вершины — 5–7 часов. Спуск по маршруту 2Б.'),
  ('227d6ee2-e2af-5ad6-a6a9-c87432dd5713', '1546945c-eba7-5f41-8c64-c446145e013c', '— Траверс пиков Озерный — Химик, 3А', 3, 'Июль — сентябрь', 'Категория: 3А. Тип: комбинированный. Вершина: Химик.

Описание маршрута:
От альпбазы «Уллутау» через спортплощадку, откуда начинается тропа, затем вдоль ручья (слева от ручья), стекающего из-под ледника на Северном склоне пика «Треугольник». Далее тропа поворачивает налево и идёт по скальным выступам к учебным скалам «над лагерем». Далее двигаться нужно по травянистым склонам на верх моренных отложений и далее по моренным отложениям и взлётам вверх мимо цирков вершин Треугольник и Московский комсомолец до Озёрного озера. У озера площадки для бивуака.
Обойдя озеро справа выходите на ледник Озёрный. Прямо будет перемычка между пиками Зимний и Озерный. Далее по кулуару вверх-вправо мимо скальных островов (справа) на перемычку. Первый жандарм обходится слева по полкам, затем выход направо на гребень и далее по гребню до следующего жандарма, который обойти справа по полкам и выйти на большую снежную перемычку. Далее по некрутому снежно-ледовому склону до провала в гребне, короткий дольфер (5–7 м). По скалам вверх — п. Озерный.
Путь от Озерной к пику Химик идёт вначале по простому скальному, возможно заснеженному со снежными карнизами гребню. Затем спуск влево по снежнику 30–40 м в мульду, из которой вправо-вверх подъём на жандарм Простой. От жандарма влево и вверх по снежным взлётам выйти на вершину пика Химик. Спуск с пика Химик по маршруту 2Б.'),
  ('3713d2e1-468b-5a65-bc76-d5a32a4380d6', 'fc4d3311-ebf9-5a61-8b84-9ac19705ce11', '— Джайлык по Северному склону Западного гребня', 4, 'Июль — сентябрь', 'Категория: 4А. Тип: комбинированный. Вершина: Джайлык.

Описание маршрута:
R0: От площадок напротив «Чёрных скал» Джайлыковского забора по морене до языка ледника Зап. Джайлык. По леднику подойти к осыпному взлёту справа от бараньих лбов и текущему по ним ручью. По сыпухе выход на плечо Западного гребня вершины Джайлык. От плеча прямо под ледово-снежные склоны Зап. гребня. Вначале подъём по пологому, затем по крутому ледово-снежному 400–500-метровому склону северной (левой по ходу) стороны Западного гребня вершины Джайлык.
R1: Далее подъём в характерную седловину у основания Западного гребня (1 верёвка). Справа от неё большой жандарм. От седловины начинается простой скальный гребень из разрушенных скал II–III к.сл. до широкой осыпной площадки. Длина этого участка гребня 35–40 м.
R2: Выйдя на широкую осыпную площадку, подходите ко второму «жандарму» с отвесными стенами на С-3 и Ю-В. Этот «жандарм» можно обойти слева по снежно-ледовому кулуару. Пройдя по кулуару 35–40 м, подняться по 5-ти метровой косой полке, подводящей к пологой плите. Жандарм также можно обойти по скалам справа. Сначала траверсом по полке вправо и далее по спирали влево-вверх на вершину узкого гребня перед широкой пологой плитой под скальной стеной гребня. Скалы IV к.сл.
R3: По широкой наклонной плите подойти под стену. Здесь есть станция на шлямбуре и морковке. Далее будет ключевое место маршрута. С плиты приспуститься вправо 1–1,5 м и по расщелине в отвесной стене без зацепок для ног 2 м до горизонтальной полки. В расщелине есть две петли, за которые можно придержаться и использовать для ИТО, повесив лесенку или оттяжку. Дальше вверх и влево идёт 40-метровый скальный кулуар — внутренний угол с натечным льдом на скалах (скалы IV+, V трудности). В конце кулуара траверс на его правую стенку и выход на большую площадку.
R4: От контрольного тура 2 верёвки на плечо контрфорса, к которому ведёт простой скальный кулуар. С плеча контрфорса прямо вверх на 10–12 м и далее вправо на полку. Здесь есть место под палатку. Далее вверх на достаточно простой участок короткого гребня и спуск с него по внутреннему углу на перемычку перед жандармом «Гриб», который обходится справа.
R4 (вар.): С перемычки короткий дольфер направо и далее по полкам правой части жандарма на маленькую полку с отколом, где можно организовать станцию. От полки с отколом снова короткий дольфер вправо вниз и далее по полкам к левой части кулуара. По границе скал, придерживаясь левой стороной широкого кулуара поднимаемся на снежное плечо, с которого спускаются крутые снежные склоны на юго-восток и север. По некрутому снежно-ледовому северному склону (50–60 м) поднимаемся на вершинный гребень.
R5: По правой части вершинного гребня по широким полкам с одновременной страховкой до короткого дольфера в провал у основания кулуара. Далее по простым скалам справа налево по спирали выход на вершину Джайлык.
Расчёт времени: Бивуак напротив чёрных скал — контрольный тур — 6–7 часов. От контрольного тура до вершины — 3,5–4 часа.'),
